// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PostingBoard {
    struct Post {
        address author;
        string content;
        uint256 totalPower;
    }

    mapping(uint256 => Post) public posts;
    mapping(address => uint256) public authorBalances;
    uint256 public postCount;

    event PostCreated(uint256 indexed postId, address indexed author, string content);
    event PostBoosted(uint256 indexed postId, uint256 amount);
    event Withdrawal(address indexed author, uint256 amount);

    function createPost(string calldata content) public returns (uint256) {
        require(bytes(content).length > 0, "Content cannot be empty");
        postCount++;
        posts[postCount] = Post({
            author: msg.sender,
            content: content,
            totalPower: 0
        });
        emit PostCreated(postCount, msg.sender, content);
        return postCount;
    }

    function getPost(uint256 postId) public view returns (address author, string memory content, uint256 totalPower) {
        Post memory post = posts[postId];
        require(post.author != address(0), "Post does not exist");
        return (post.author, post.content, post.totalPower);
    }

    function boostPost(uint256 postId) public payable {
        require(postId <= postCount, "Post does not exist");
        require(msg.value > 0, "Value must be greater than 0");
        require(posts[postId].author != msg.sender, "Author cannot boost their own post");

        Post storage post = posts[postId];
        post.totalPower += msg.value;
        authorBalances[post.author] += msg.value;
        emit PostBoosted(postId, msg.value);
    }

    function authorBalancesOf(address author) public view returns (uint256) {
        return authorBalances[author];
    }

    function withdraw() public {
        uint256 balance = authorBalances[msg.sender];
        require(balance > 0, "No balance to withdraw");

        authorBalances[msg.sender] = 0;
        (bool sent, ) = msg.sender.call{value: balance}("");
        require(sent, "Failed to send Ether");

        emit Withdrawal(msg.sender, balance);
    }
}
